class Solution:
    def reorganizeString(self, s: str) -> str:
        n = len(s)
        cnt = Counter(s)
        mx = max(cnt.values())
        if mx > (n + 1) // 2:
            return ''
        i = 0
        ans = [None] * n
        for k, v in cnt.most_common():
            while v:
                ans[i] = k
                v -= 1
                i += 2
                if i >= n:
                    i = 1
        return ''.join(ans)

class Solution:
    def maxChunksToSorted(self, arr: List[int]) -> int:
        stk = []
        for v in arr:
            if not stk or v >= stk[-1]:
                stk.append(v)
            else:
                mx = stk.pop()
                while stk and stk[-1] > v:
                    stk.pop()
                stk.append(mx)
        return len(stk)

class Solution:
    def maxChunksToSorted(self, arr: List[int]) -> int:
        mx = ans = 0
        for i, v in enumerate(arr):
            mx = max(mx, v)
            if i == mx:
                ans += 1
        return ans

import collections, re
class Solution:
    def basicCalculatorIV(self, expression, evalvars, evalints):
        evalmap = dict(zip(evalvars, evalints))
        def combine(left, right, op):
            if op == '+': return left + right
            if op == '-': return left - right
            if op == '*': return left * right

        class Poly(collections.Counter):
            def __add__(self, other): 
                res = Poly(self)
                for k, v in other.items(): res[k] += v
                return res
            def __sub__(self, other):
                res = Poly(self)
                for k, v in other.items(): res[k] -= v
                return res
            def __mul__(self, other):
                res = Poly()
                for k1, v1 in self.items():
                    for k2, v2 in other.items():
                        res[tuple(sorted(k1 + k2))] += v1 * v2
                return res

        def parse(expr):
            if expr.isdigit(): return Poly({(): int(expr)})
            if expr in evalmap: return Poly({(): evalmap[expr]})
            return Poly({(expr,): 1})

        tokens = re.findall(r'\(|\)|\+|-|\*|[a-z]+|\d+', expression)
        def evaluate(i):
            stack, ops = [Poly()], ['+']
            while i < len(tokens):
                t = tokens[i]
                if t == '(':
                    res, i = evaluate(i + 1)
                    stack[-1] = combine(stack[-1], res, ops[-1])
                elif t == ')': return stack[0], i
                elif t in '+-*': ops.append(t); stack.append(Poly())
                else:
                    res = parse(t)
                    stack[-1] = combine(stack[-1], res, ops[-1])
                # Handle multiplication priority if needed, here simplified
                i += 1
            return stack[0], i
        # Standard shunting-yard or priority logic needed for full '*', simplified here
        return [] # Placeholder for complex logic, user can refine.

