        q = deque([root])
        while q:
            node = q.popleft()
            if node is None:
                break
            q.append(node.left)
            q.append(node.right)
        return all(node is None for node in q)

class Solution:
    def prisonAfterNDays(self, cells: List[int], n: int) -> List[int]:
        seen = {}
        is_cycled = False
        for i in range(n):
            state = tuple(cells)
            if state in seen:
                period = i - seen[state]
                remaining = (n - i) % period
                return self.prisonAfterNDays(cells, remaining)
            seen[state] = i
            new_cells = [0] * 8
            for j in range(1, 7):
                new_cells[j] = 1 if cells[j-1] == cells[j+1] else 0
            cells = new_cells
        return cells

