from fractions import Fraction
class Solution:
    def isRationalEqual(self, s: str, t: str) -> bool:
        def convert(s):
            if '(' not in s:
                return Fraction(s)
            i = s.find('.')
            j = s.find('(')
            k = s.find(')')
            # Part before dot
            res = Fraction(s[:i])
            # Non-repeating fractional part
            non_repeat = s[i+1:j]
            if non_repeat:
                res += Fraction(int(non_repeat), 10**len(non_repeat))
            # Repeating fractional part
            repeat = s[j+1:k]
            denom = (10**len(repeat) - 1) * (10**len(non_repeat))
            res += Fraction(int(repeat), denom)
            return res
        return convert(s) == convert(t)

