        dp = [[0]*(m+1) for _ in range(n+1)]
        for i in range(n):
            for j in range(m):
                if str1[i] == str2[j]: dp[i+1][j+1] = dp[i][j] + 1
                else: dp[i+1][j+1] = max(dp[i][j+1], dp[i+1][j])
        res = []
        i, j = n, m
        while i > 0 or j > 0:
