class FizzBuzz:
    def __init__(self, n: int):
        self.n = n
        self.curr = 1
        self.cv = threading.Condition()
    def fizz(self, printFizz: 'Callable[[], None]') -> None:
        while True:
            with self.cv:
                while self.curr <= self.n and (self.curr % 3 != 0 or self.curr % 5 == 0):
                    self.cv.wait()
                if self.curr > self.n: break
                printFizz(); self.curr += 1; self.cv.notify_all()
    def buzz(self, printBuzz: 'Callable[[], None]') -> None:
        while True:
            with self.cv:
                while self.curr <= self.n and (self.curr % 5 != 0 or self.curr % 3 == 0):
                    self.cv.wait()
                if self.curr > self.n: break
                printBuzz(); self.curr += 1; self.cv.notify_all()
    def fizzbuzz(self, printFizzBuzz: 'Callable[[], None]') -> None:
        while True:
            with self.cv:
                while self.curr <= self.n and (self.curr % 15 != 0):
                    self.cv.wait()
                if self.curr > self.n: break
                printFizzBuzz(); self.curr += 1; self.cv.notify_all()
    def number(self, printNumber: 'Callable[[int], None]') -> None:
        while True:
            with self.cv:
                while self.curr <= self.n and (self.curr % 3 == 0 or self.curr % 5 == 0):
                    self.cv.wait()
                if self.curr > self.n: break
                printNumber(self.curr); self.curr += 1; self.cv.notify_all()

